public:
    bool isLongPressedName(string name, string typed) {
        int i = 0, j = 0;
        int n = name.size(), m = typed.size();
        while (i < n && j < m) {
            if (name[i] != typed[j]) return false;
            char c = name[i];
            int cntName = 0;
            while (i < n && name[i] == c) {
                ++i;
                ++cntName;
            }
            int cntTyped = 0;
            while (j < m && typed[j] == c) {
                ++j;
                ++cntTyped;
            }
            if (cntTyped < cntName) return false;
        }
        return i == n && j == m;
    }
};
